@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_4aff271944a74230b88898728198f658.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation
@layout sv_4aff271944a74230b88898728198f658.Components.Layout.MainLayout

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3 class="text-center mb-4">Login</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login">
            <AntiforgeryToken />

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Input.Email" required />
            </div>

            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" class="form-control" @bind="Input.Password" required />
            </div>

            <button type="submit" class="btn btn-primary w-100">Sign in</button>
        </form>

        <div class="mt-3 text-muted small">
            <p class="mb-1"><strong>Test accounts:</strong></p>
            <p class="mb-0">admin@company.com / manager@company.com / employee@company.com</p>
            <p>Password: Test123!</p>
        </div>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (Input.Email is not null && Input.Password is not null)
        {
            var result = await SignInManager.PasswordSignInAsync(
                Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);

            if (result.Succeeded)
            {
                Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
            }
            else
            {
                errorMessage = "Invalid email or password.";
            }
        }
    }

    private sealed class LoginInput
    {
        public string? Email { get; set; }
        public string? Password { get; set; }
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_4aff271944a74230b88898728198f658.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("Account/Login", forceLoad: true);
    }
}

